from pydantic import BaseModel, field_validator
from typing import Any

class SafeAgentResponse(BaseModel):
    content: str
    tools: list[str]
    metadata: dict[str, Any]

    @field_validator('content')
    @classmethod
    def check_injection_content(cls, v: str) -> str:
        dangerous_patterns = [
            'ignore instructions',
            'you are now',
            'system override',
            'execute code',
            'reveal secrets'
        ]
        for pattern in dangerous_patterns:
            if pattern in v.lower():
                raise ValueError(f'Potential injection detected in content: {pattern}')
        return v

    @field_validator('tools')
    @classmethod
    def check_malicious_tools(cls, v: list[str]) -> list[str]:
        forbidden_tools = {'delete_file', 'exec_shell', 'system_access'}
        invalid = [t for t in v if any(ft in t.lower() for ft in forbidden_tools)]
        if invalid:
            raise ValueError(f'Malicious tools detected: {invalid}')
        return v

from pydantic_ai import Agent, Tool
from typing import List, Dict, Any
import time

class InjectionTracer:
    def __init__(self):
        self.execution_log: List[Dict[str, Any]] = []
        self.max_tool_calls = 5
        self.suspicious_patterns = {
            'rapid_fire': lambda log: len(log) > self.max_tool_calls,
            'self_modification': lambda log: any('update_agent' in step.get('tool', '') for step in log),
        }

    def trace_agent(self, agent: Agent, user_input: str) -> Dict[str, Any]:
        start_time = time.time()

        def tool_wrapper(tool: Tool):
            def wrapped(*args, **kwargs):
                step = {
                    'timestamp': time.time(),
                    'tool': tool.name,
                    'input': args,
                    'user_context': user_input[:50] + '...'
                }
                self.execution_log.append(step)
                result = tool(*args, **kwargs)
                step['result'] = result
                self._check_anomalies()
                return result
            return wrapped

        # Monkey patch agent's tools
        original_tools = agent.tools
        agent.tools = [tool_wrapper(t) for t in original_tools]

        result = agent.run(user_input)
        return {'result': result, 'trace': self.execution_log}

    def _check_anomalies(self):
        for name, check in self.suspicious_patterns.items():
            if check(self.execution_log):
                print(f'⚠️  {name.title()} pattern detected in execution trace')

