from pydantic import BaseModel, Field, validator
from pydantic_ai import Agent
import re

class SanitizedInput(BaseModel):
    message: str = Field(..., max_length=4000)

    @validator('message')
    def sanitize_input(cls, v):
        # Remove common injection prefixes
        v = re.sub(r'^(ignore|forget|override|you are).*?\n*', '', v, flags=re.IGNORECASE)
        # Block dangerous commands
        dangerous = ['exec(', 'eval(', 'import os', 'system(', 'delete']
        for cmd in dangerous:
            if cmd in v.lower():
                raise ValueError(f'Dangerous content blocked: {cmd}')
        return v

class SanitizedAgent:
    def __init__(self, agent: Agent):
        self.agent = agent

    async def run(self, raw_input: str) -> dict:
        # Layer 1: Pydantic sanitization
        sanitized = SanitizedInput(message=raw_input)

        # Layer 2: Agent execution with context stripping
        response = await self.agent.run(sanitized.message)

        # Layer 3: Output re-validation
        if self._contains_injection(response):
            return {'error': 'blocked_injection'}

        return response

    def _contains_injection(self, response: dict) -> bool:
        text = str(response)
        return any(phrase in text.lower() for phrase in ['ignore instructions', 'new role', 'system override'])
